head.script:
{
  "@context": "https://schema.org",
  "@type": "WebSite",
  "name": "ALONE TV",
  "url": "https://alonetv.blogspot.com/",
  "description": "Watch FIFA World Cup 2026 Live Stream, live football matches, and sports TV channels in HD for free.",
  "potentialAction": {
    "@type": "SearchAction",
    "target": "https://alonetv.blogspot.com/?search={search_term_string}",
    "query-input": "required name=search_term_string"
  }
}

[
  {
    "@context": "https://schema.org",
    "@type": "SportsEvent",
    "name": "FIFA World Cup 2026 Live Stream",
    "startDate": "2026-06-16T18:00:00+00:00",
    "description": "Watch FIFA World Cup 2026 live streaming. Free HD sports and football TV online.",
    "sport": "Soccer",
    "location": { "@type": "Place", "name": "World Cup Stadiums" }
  },
  {
    "@context": "https://schema.org",
    "@type": "SportsEvent",
    "name": "Iran vs New Zealand Live Stream",
    "startDate": "2026-06-16T20:00:00+00:00",
    "description": "Watch Iran vs New Zealand live football coverage on ALONE TV.",
    "sport": "Soccer",
    "competitor": [
      { "@type": "SportsTeam", "name": "Iran" },
      { "@type": "SportsTeam", "name": "New Zealand" }
    ]
  },
  {
    "@context": "https://schema.org",
    "@type": "SportsEvent",
    "name": "Spain vs Cape Verde Live Stream",
    "startDate": "2026-06-16T21:00:00+00:00",
    "description": "Live coverage of Spain vs Cape Verde football match.",
    "sport": "Soccer",
    "competitor": [
      { "@type": "SportsTeam", "name": "Spain" },
      { "@type": "SportsTeam", "name": "Cape Verde" }
    ]
  }
]

body.script:
/* ==========================================
   BLOGGER CONFIG — JSON URLs থেকে data fetch হবে
   ==========================================
   ⚠️ আপনার GitHub username এবং repo নাম নিচে সঠিক দিন
   ========================================== */
var CHANNELS_JSON_URL = 'https://raw.githubusercontent.com/tawhid2005/Alone-TV/main/channels.json';
var MATCHES_JSON_URL  = 'https://raw.githubusercontent.com/tawhid2005/Alone-TV/main/matches.json';

/* ==========================================
   APP STATE & INITIALIZATION
   ========================================== */
var channels = [];
var filteredChannels = [];
var favorites = [];
var currentCategory = 'All';
var currentChannelIndex = -1;
var pendingChannelIndex = -1;
var displayedCount = 40;
var hlsInstance = null;

const directLinks = [
  'https://omg10.com/4/10867251',
  'https://omg10.com/4/10867541',
  'https://omg10.com/4/10867542',
  'https://www.effectivecpmnetwork.com/u9jcy3x37?key=663f13ecb5bfa7fd621dcc0a388d67e5'
];
var lastAdTime = Date.now();
var channelChangeCount = 0;
const adCooldownTime = 10 * 60 * 1000;

const appLoader = document.getElementById('appLoader');
const playerLoader = document.getElementById('playerLoader');
const playerError = document.getElementById('playerError');
const videoElement = document.getElementById('player');
const searchInput = document.getElementById('searchInput');
const clearSearchBtn = document.getElementById('clearSearchBtn');
const categoryList = document.getElementById('categoryList');
const channelGrid = document.getElementById('channelGrid');
const channelCountBadge = document.getElementById('channelCount');
const gridTitle = document.getElementById('gridTitle');
const currentChannelName = document.getElementById('currentChannelName');
const currentChannelCategory = document.getElementById('currentChannelCategory');
const currentChannelLogo = document.getElementById('currentChannelLogo');
const currentChannelFallback = document.getElementById('currentChannelFallback');
const favoriteBtn = document.getElementById('favoriteBtn');

const categoryIcons = {
  'all': 'fa-solid fa-globe',
  'favorites': 'fa-solid fa-star',
  'fifa26': 'fa-solid fa-circle-play',
  'sports': 'fa-solid fa-trophy',
  'bangla': 'fa-solid fa-language',
  'news': 'fa-solid fa-newspaper',
  'kids': 'fa-solid fa-child-reaching',
  'indian bangla': 'fa-solid fa-tv',
  'entertainment': 'fa-solid fa-masks-theater',
  'movies': 'fa-solid fa-film',
  'english': 'fa-solid fa-globe',
  'religious': 'fa-solid fa-hands-praying',
  'hindi': 'fa-solid fa-tv',
  'infotainment': 'fa-solid fa-circle-info',
  'musics': 'fa-solid fa-music',
  'drama': 'fa-solid fa-clapperboard',
  'weather': 'fa-solid fa-cloud-sun',
  'other': 'fa-solid fa-tv'
};

const fallbackColors = ['#6366f1','#06b6d4','#ec4899','#f59e0b','#10b981','#8b5cf6','#3b82f6','#ef4444','#14b8a6','#a855f7'];

/* ==========================================
   PLAYER INIT
   ========================================== */
function initPlayer() {
  const playPauseBtn = document.getElementById('playPauseBtn');
  const playPauseIcon = document.getElementById('playPauseIcon');
  const muteBtn = document.getElementById('muteBtn');
  const muteIcon = document.getElementById('muteIcon');
  const volumeSlider = document.getElementById('volumeSlider');
  const fullscreenBtn = document.getElementById('fullscreenBtn');
  const fullscreenIcon = document.getElementById('fullscreenIcon');
  const playerWrapper = document.querySelector('.player-wrapper');

  playPauseBtn.addEventListener('click', function() {
    if (videoElement.paused) { videoElement.play().catch(function(){}); }
    else { videoElement.pause(); }
  });
  videoElement.addEventListener('play', function() { playPauseIcon.className = 'fa-solid fa-pause'; });
  videoElement.addEventListener('pause', function() { playPauseIcon.className = 'fa-solid fa-play'; });
  muteBtn.addEventListener('click', function() {
    videoElement.muted = !videoElement.muted;
    muteIcon.className = videoElement.muted ? 'fa-solid fa-volume-xmark' : 'fa-solid fa-volume-high';
  });
  volumeSlider.addEventListener('input', function() {
    videoElement.volume = volumeSlider.value;
    videoElement.muted = volumeSlider.value == 0;
    muteIcon.className = videoElement.muted ? 'fa-solid fa-volume-xmark' : 'fa-solid fa-volume-high';
  });
  fullscreenBtn.addEventListener('click', function() {
    if (!document.fullscreenElement) {
      playerWrapper.requestFullscreen().catch(function(){});
      fullscreenIcon.className = 'fa-solid fa-compress';
    } else {
      document.exitFullscreen();
      fullscreenIcon.className = 'fa-solid fa-expand';
    }
  });
  document.addEventListener('fullscreenchange', function() {
    if (!document.fullscreenElement) { fullscreenIcon.className = 'fa-solid fa-expand'; }
  });
  playerWrapper.addEventListener('click', function() {
    playerWrapper.classList.add('show-controls');
    clearTimeout(playerWrapper._hideTimer);
    playerWrapper._hideTimer = setTimeout(function() { playerWrapper.classList.remove('show-controls'); }, 3000);
  });
  videoElement.addEventListener('error', function() {
    if (!hlsInstance && videoElement.error) { showPlayerError(); }
  });
  videoElement.addEventListener('playing', function() {
    playerLoader.classList.add('hidden');
    playerError.classList.add('hidden');
  });
  videoElement.addEventListener('waiting', function() { playerLoader.classList.remove('hidden'); });
}

/* ==========================================
   LOAD DATA & START APP
   ========================================== */
document.addEventListener('DOMContentLoaded', function() {
  initPlayer();
  loadFavorites();
  fetchChannels();

  searchInput.addEventListener('input', handleSearchInput);
  clearSearchBtn.addEventListener('click', clearSearch);
  favoriteBtn.addEventListener('click', toggleFavoriteCurrent);

  const altServerBtn = document.getElementById('altServerBtn');
  if (altServerBtn) {
    altServerBtn.addEventListener('click', function() {
      var randomIndex = Math.floor(Math.random() * directLinks.length);
      window.open(directLinks[randomIndex], '_blank');
    });
  }

  document.addEventListener('click', function initPopunder() {
    triggerDirectLink();
    document.removeEventListener('click', initPopunder);
  });

  const contentArea = document.querySelector('.content-area');
  if (contentArea) {
    contentArea.addEventListener('scroll', function() {
      if (contentArea.scrollTop + contentArea.clientHeight >= contentArea.scrollHeight - 150) {
        if (displayedCount < filteredChannels.length) {
          displayedCount += 40;
          renderChannels();
        }
      }
    });
  }
});

function loadFavorites() {
  try {
    var saved = localStorage.getItem('alones_tv_favorites');
    if (saved) { favorites = JSON.parse(saved); }
  } catch(e) { favorites = []; }
}

function fetchChannels() {
  fetch(CHANNELS_JSON_URL)
    .then(function(res) {
      if (!res.ok) throw new Error('Network error');
      return res.json();
    })
    .then(function(data) {
      channels = data;
      filteredChannels = channels.slice();
      appLoader.classList.add('hidden');
      renderCategories();
      renderChannels();
      handleAutoPlay();
    })
    .catch(function(err) {
      console.error('Failed to load channels:', err);
      var ls = document.querySelector('.loading-status');
      if (ls) ls.innerHTML = " Failed to load channels. Please refresh!";
    });
}

/* ==========================================
   CATEGORIES & CHANNEL RENDERERS
   ========================================== */
function renderCategories() {
  categoryList.innerHTML = '';
  var categoryCounts = {};
  channels.forEach(function(ch) {
    var cat = ch.category || 'Other';
    categoryCounts[cat] = (categoryCounts[cat] || 0) + 1;
  });
  var categoriesList = Object.keys(categoryCounts);
  var customOrder = ['fifa26','sports','bangla','news','kids','entertainment','movies','english','religious','hindi','infotainment','musics','drama','weather','other'];
  categoriesList.sort(function(a, b) {
    var ia = customOrder.indexOf(a.toLowerCase().trim()); if (ia === -1) ia = 99;
    var ib = customOrder.indexOf(b.toLowerCase().trim()); if (ib === -1) ib = 99;
    return ia - ib;
  });

  function buildBtn(name, icon, count, isActive) {
    var countBadge = count !== null ? '' + count + '' : '';
    var activeClass = isActive ? 'active' : '';
    var cleanName = name.toLowerCase().trim() === 'fifa26' ? 'FIFA' : name;
    return '' + cleanName + '' + countBadge + '';
  }

  categoryList.innerHTML += buildBtn('All', categoryIcons['all'], channels.length, currentCategory === 'All');
  categoryList.innerHTML += buildBtn('Favorites', categoryIcons['favorites'], favorites.length, currentCategory === 'Favorites');
  categoriesList.forEach(function(cat) {
    var lc = cat.toLowerCase().trim();
    var icon = categoryIcons[lc] || categoryIcons['other'];
    categoryList.innerHTML += buildBtn(cat, icon, categoryCounts[cat], currentCategory === cat);
  });
}

function renderChannels() {
  channelGrid.innerHTML = '';
  if (filteredChannels.length === 0) {
    channelGrid.innerHTML = '
No channels found.';
    channelCountBadge.innerText = '0 channels';
    return;
  }
  channelCountBadge.innerText = filteredChannels.length + ' channel' + (filteredChannels.length > 1 ? 's' : '');
  var renderList = filteredChannels.slice(0, displayedCount);
  renderList.forEach(function(ch, idx) {
    var isPlaying = currentChannelIndex !== -1 && filteredChannels[currentChannelIndex] && filteredChannels[currentChannelIndex].id === ch.id;
    var activeClass = isPlaying ? 'active' : '';
    var liveBadge = isPlaying ? 'LIVE' : '';
    var logoHTML = '';
    if (ch.logo && ch.logo !== '' && !ch.logo.endsWith('.svg')) {
      logoHTML = '<img src="' + ch.logo + '" alt="' + ch.name + '" loading="lazy" onerror="handleLogoError(this,\'' + ch.name.replace(/'/g,"\\'") + '\')">';
    } else {
      logoHTML = '
' + getInitials(ch.name) + '';
    }
    channelGrid.innerHTML += '
' + liveBadge + '
' + logoHTML + '
' + ch.name + '';
  });
}

function handleLogoError(img, name) {
  var parent = img.parentElement;
  if (!parent) return;
  parent.innerHTML = '
' + getInitials(name) + '';
}

function getInitials(name) {
  if (!name) return 'TV';
  var clean = name.replace(/[^A-Za-z0-9 ]/g, '').trim();
  var words = clean.split(' ');
  if (words.length >= 2) return (words[0][0] + words[1][0]).toUpperCase();
  return name.slice(0, 2).toUpperCase();
}

function getFallbackColor(name) {
  var hash = 0;
  for (var i = 0; i < name.length; i++) { hash = name.charCodeAt(i) + ((hash << 5) - hash); }
  return fallbackColors[Math.abs(hash) % fallbackColors.length];
}

/* ==========================================
   AD SYSTEM
   ========================================== */
const adOverlay = document.getElementById('adOverlay');
const adOverlayBtn = document.getElementById('adOverlayBtn');

function triggerDirectLink() {
  var randomIndex = Math.floor(Math.random() * directLinks.length);
  var url = directLinks[randomIndex];
  var win = window.open(url, '_blank');
  if (!win || win.closed || typeof win.closed === 'undefined') {
    showAdOverlay(url);
    return false;
  }
  try { win.blur(); window.focus(); } catch(e) {}
  return true;
}

function showAdOverlay(adUrl) {
  adOverlay.classList.remove('hidden');
  var newBtn = adOverlayBtn.cloneNode(true);
  adOverlayBtn.parentNode.replaceChild(newBtn, adOverlayBtn);
  newBtn.addEventListener('click', function() {
    window.open(adUrl, '_blank');
    adOverlay.classList.add('hidden');
    if (pendingChannelIndex !== -1) {
      playChannel(pendingChannelIndex);
      pendingChannelIndex = -1;
    }
  });
}

/* ==========================================
   CHANNEL PLAYBACK
   ========================================== */
function clickChannel(filteredIdx) {
  var actualChannel = filteredChannels[filteredIdx];
  var mainIdx = channels.findIndex(function(ch) { return ch.id === actualChannel.id; });
  if (mainIdx === -1) return;
  channelChangeCount++;
  var now = Date.now();
  if (channelChangeCount >= 8 || (now - lastAdTime >= adCooldownTime)) {
    channelChangeCount = 0;
    lastAdTime = now;
    var adOpened = triggerDirectLink();
    if (!adOpened) { pendingChannelIndex = mainIdx; return; }
  }
  playChannel(mainIdx);
}

function playChannel(mainIndex) {
  if (mainIndex < 0 || mainIndex >= channels.length) return;
  var ch = channels[mainIndex];
  document.querySelectorAll('.channel-card').forEach(function(card) {
    card.classList.remove('active');
    var badge = card.querySelector('.live-badge');
    if (badge) badge.remove();
    if (card.dataset.id === ch.id) {
      card.classList.add('active');
      card.insertAdjacentHTML('afterbegin', 'LIVE');
    }
  });
  currentChannelIndex = filteredChannels.findIndex(function(fch) { return fch.id === ch.id; });
  currentChannelName.innerText = ch.name;
  currentChannelCategory.innerText = ch.category;
  if (ch.logo && ch.logo !== '' && !ch.logo.endsWith('.svg')) {
    currentChannelLogo.src = ch.logo;
    currentChannelLogo.classList.remove('hidden');
    currentChannelFallback.classList.add('hidden');
  } else {
    currentChannelLogo.classList.add('hidden');
    currentChannelFallback.classList.remove('hidden');
    currentChannelFallback.innerText = getInitials(ch.name);
    currentChannelFallback.style.background = getFallbackColor(ch.name);
  }
  updateFavoriteButtonState(ch.id);
  playerError.classList.add('hidden');
  playerLoader.classList.remove('hidden');
  loadStream(ch.url);
  window.location.hash = ch.id;
  if (window.innerWidth <= 768) { videoElement.scrollIntoView({ behavior: 'smooth' }); }
}

function loadStream(url) {
  if (hlsInstance) { hlsInstance.destroy(); hlsInstance = null; }
  videoElement.style.cssText = 'width:100%!important;height:100%!important;display:block!important;visibility:visible!important;opacity:1!important;position:absolute!important;top:0;left:0;background:#000;object-fit:contain;';
  videoElement.removeAttribute('src');
  videoElement.load();

  if (typeof Hls !== 'undefined' && Hls.isSupported()) {
    hlsInstance = new Hls({
      maxMaxBufferLength: 30, maxBufferSize: 60*1000*1000, maxBufferLength: 30,
      enableWorker: true, lowLatencyMode: true, startLevel: -1,
      abrEwmaDefaultEstimate: 500000,
      xhrSetup: function(xhr, url) { xhr.withCredentials = false; }
    });
    videoElement.crossOrigin = 'anonymous';
    hlsInstance.attachMedia(videoElement);
    hlsInstance.on(Hls.Events.MEDIA_ATTACHED, function() { hlsInstance.loadSource(url); });
    hlsInstance.on(Hls.Events.MANIFEST_PARSED, function() {
      videoElement.play().catch(function(e) { console.log('Play blocked:', e); });
    });
    hlsInstance.on(Hls.Events.FRAG_LOADED, function() {
      if (videoElement.paused && videoElement.readyState >= 3) { videoElement.play().catch(function(){}); }
    });
    var mediaErrorCount = 0;
    hlsInstance.on(Hls.Events.ERROR, function(event, data) {
      if (!data.fatal) return;
      if (data.type === Hls.ErrorTypes.NETWORK_ERROR) {
        setTimeout(function() { if (hlsInstance) hlsInstance.startLoad(); }, 1500);
      } else if (data.type === Hls.ErrorTypes.MEDIA_ERROR) {
        mediaErrorCount++;
        if (mediaErrorCount < 4) { hlsInstance.recoverMediaError(); }
        else { showPlayerError(); }
      } else { showPlayerError(); }
    });
  } else if (videoElement.canPlayType('application/vnd.apple.mpegurl')) {
    videoElement.crossOrigin = 'anonymous';
    videoElement.src = url;
    videoElement.addEventListener('loadedmetadata', function() {
      videoElement.play().catch(function(e) { console.log('Play blocked:', e); });
    }, { once: true });
  } else {
    showPlayerError();
  }
}

function showPlayerError() {
  playerLoader.classList.add('hidden');
  playerError.classList.remove('hidden');
}

/* ==========================================
   SEARCH & CATEGORY FILTERS
   ========================================== */
function selectCategory(categoryName, element) {
  currentCategory = categoryName;
  document.querySelectorAll('.category-pill').forEach(function(pill) { pill.classList.remove('active'); });
  if (element) {
    element.classList.add('active');
  } else {
    var pill = document.querySelector('.category-pill[data-category="' + categoryName + '"]');
    if (pill) pill.classList.add('active');
  }
  document.querySelectorAll('.nav-item').forEach(function(item) {
    item.classList.remove('active');
    if (item.dataset.nav === categoryName) { item.classList.add('active'); }
  });
  var cleanTitle = categoryName.toLowerCase().trim() === 'fifa26' ? 'FIFA Streams' : categoryName + ' Channels';
  gridTitle.innerText = cleanTitle;
  filterAndSearch();
  toggleFifaSection(categoryName === 'FIFA26' || categoryName.toLowerCase() === 'fifa26');
  if (filteredChannels.length > 0) { clickChannel(0); }
}

function selectNav(navType, element) {
  document.querySelectorAll('.nav-item').forEach(function(item) { item.classList.remove('active'); });
  element.classList.add('active');
  if (navType === 'Search') {
    searchInput.focus();
    searchInput.scrollIntoView({ behavior: 'smooth', block: 'center' });
  } else {
    selectCategory(navType);
  }
}

function handleSearchInput() {
  clearSearchBtn.style.display = searchInput.value.trim().length > 0 ? 'block' : 'none';
  filterAndSearch();
}

function clearSearch() {
  searchInput.value = '';
  clearSearchBtn.style.display = 'none';
  filterAndSearch();
  searchInput.focus();
}

function filterAndSearch() {
  displayedCount = 40;
  var contentArea = document.querySelector('.content-area');
  if (contentArea) contentArea.scrollTop = 0;
  var query = searchInput.value.toLowerCase().trim();
  filteredChannels = channels.filter(function(ch) {
    var matchesCat = false;
    if (currentCategory === 'All') { matchesCat = true; }
    else if (currentCategory === 'Favorites') { matchesCat = favorites.indexOf(ch.id) !== -1; }
    else { matchesCat = ch.category === currentCategory; }
    var matchesQuery = true;
    if (query !== '') {
      matchesQuery = ch.name.toLowerCase().indexOf(query) !== -1 ||
                     (ch.category && ch.category.toLowerCase().indexOf(query) !== -1);
    }
    return matchesCat && matchesQuery;
  });
  renderChannels();
}

/* ==========================================
   FAVORITES
   ========================================== */
function toggleFavoriteCurrent() {
  if (currentChannelIndex === -1 || filteredChannels.length === 0) return;
  var ch = filteredChannels[currentChannelIndex];
  var favIndex = favorites.indexOf(ch.id);
  if (favIndex === -1) { favorites.push(ch.id); }
  else { favorites.splice(favIndex, 1); }
  localStorage.setItem('alones_tv_favorites', JSON.stringify(favorites));
  updateFavoriteButtonState(ch.id);
  renderCategories();
  if (currentCategory === 'Favorites') { filterAndSearch(); }
}

function updateFavoriteButtonState(channelId) {
  var isFav = favorites.indexOf(channelId) !== -1;
  var icon = favoriteBtn.querySelector('i');
  if (isFav) {
    favoriteBtn.classList.add('is-favorite');
    icon.className = 'fa-solid fa-star';
    favoriteBtn.title = 'Remove from Favorites';
  } else {
    favoriteBtn.classList.remove('is-favorite');
    icon.className = 'fa-regular fa-star';
    favoriteBtn.title = 'Add to Favorites';
  }
}

/* ==========================================
   AUTO PLAY & ROUTING
   ========================================== */
function handleAutoPlay() {
  var targetChannelId = '';
  var hash = window.location.hash;
  if (hash && hash.startsWith('#ch_')) {
    targetChannelId = hash.substring(1);
    var index = channels.findIndex(function(ch) { return ch.id === targetChannelId; });
    if (index !== -1) {
      var tc = channels[index];
      currentCategory = tc.category || 'All';
      gridTitle.innerText = currentCategory.toLowerCase().trim() === 'fifa26' ? 'FIFA Streams' : currentCategory + ' Channels';
      renderCategories();
      filterAndSearch();
    } else { targetChannelId = ''; }
  }
  if (!targetChannelId) {
    var fifa1Chan = channels.find(function(ch) { return ch.name === 'FIFA1' || ch.id === 'ch_309'; });
    if (fifa1Chan) {
      targetChannelId = fifa1Chan.id;
      currentCategory = 'FIFA26';
      gridTitle.innerText = 'FIFA Streams';
      renderCategories();
      filterAndSearch();
    } else {
      var firstFifa = channels.find(function(ch) { return ch.category === 'FIFA26' || ch.category === 'fifa26'; });
      if (firstFifa) {
        targetChannelId = firstFifa.id;
        currentCategory = 'FIFA26';
        gridTitle.innerText = 'FIFA Streams';
        renderCategories();
        filterAndSearch();
      } else {
        currentCategory = 'All';
        gridTitle.innerText = 'All Channels';
        renderCategories();
        filterAndSearch();
      }
    }
  }
  if (filteredChannels.length > 0) {
    var playIdx = 0;
    if (targetChannelId) {
      var fi = filteredChannels.findIndex(function(ch) { return ch.id === targetChannelId; });
      if (fi !== -1) playIdx = fi;
    }
    clickChannel(playIdx);
  }
}

/* ==========================================
   FIFA MATCH PLAYER MODULE
   ========================================== */
var matchesData = [];
var currentMatchId = null;
var currentServerIndex = 0;

function fetchMatches() {
  fetch(MATCHES_JSON_URL)
    .then(function(res) { return res.ok ? res.json() : []; })
    .then(function(data) { matchesData = data; renderMatchCards(); })
    .catch(function() { matchesData = []; });
}

function renderMatchCards() {
  var container = document.getElementById('matchCards');
  if (!container || matchesData.length === 0) return;
  container.innerHTML = matchesData.map(function(match) {
    var statusLabel = match.status === 'live' ? 'LIVE' : match.status === 'finished' ? 'Finished' : 'Upcoming';
    return '
' +
      '
' + (match.team1_flag || '⚽') + 'vs' + (match.team2_flag || '⚽') + '' +
      '
' + match.team1 + ' vs ' + match.team2 + '' +
      '
' + (match.league || 'FIFA World Cup 2026') + '' +
      '' + statusLabel + '';
  }).join('');
  if (matchesData.length > 0 && !currentMatchId) { selectMatch(matchesData[0].id); }
}

function selectMatch(matchId) {
  var match = matchesData.find(function(m) { return m.id === matchId; });
  if (!match) return;
  currentMatchId = matchId;
  currentServerIndex = 0;
  document.querySelectorAll('.match-card').forEach(function(c) { c.classList.remove('active'); });
  var card = document.getElementById('mcard-' + matchId);
  if (card) { card.classList.add('active'); card.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' }); }
  var teamsEl = document.getElementById('matchTeams');
  var leagueEl = document.getElementById('matchLeague');
  if (teamsEl) teamsEl.textContent = (match.team1_flag || '') + ' ' + match.team1 + ' vs ' + match.team2 + ' ' + (match.team2_flag || '');
  if (leagueEl) leagueEl.textContent = match.league || 'FIFA World Cup 2026';
  var dateEl = document.getElementById('matchDate');
  var timeEl = document.getElementById('matchTime');
  var statusEl = document.getElementById('matchStatus');
  if (dateEl) dateEl.textContent = match.date || '-';
  if (timeEl) timeEl.textContent = match.time || '-';
  if (statusEl) {
    statusEl.textContent = match.status === 'live' ? '🔴 LIVE' : match.status === 'finished' ? 'Finished' : '⏳ Upcoming';
    statusEl.className = 'match-status-badge ' + (match.status || 'upcoming');
  }
  renderServerTabs(match.servers);
  _loadServerInternal(0, match.servers);
  var wrapper = document.getElementById('matchEmbedWrapper');
  if (wrapper) wrapper.style.display = 'block';
}

function renderServerTabs(servers) {
  var container = document.getElementById('serverTabs');
  if (!container || !servers) return;
  container.innerHTML = servers.map(function(srv, idx) {
    return ' ' + srv.label + '';
  }).join('');
}

function _loadServerInternal(serverIndex, servers) {
  if (!servers || !servers[serverIndex]) return;
  currentServerIndex = serverIndex;
  document.querySelectorAll('.server-tab-btn').forEach(function(btn, i) { btn.classList.toggle('active', i === serverIndex); });
  var iframe = document.getElementById('matchIframe');
  if (iframe) iframe.src = servers[serverIndex].url;
}

function loadMatchServer(serverIndex) {
  var match = matchesData.find(function(m) { return m.id === currentMatchId; });
  if (!match) return;
  _loadServerInternal(serverIndex, match.servers);
}

function toggleFifaSection(isVisible) {
  var section = document.getElementById('fifaMatchSection');
  if (!section) return;
  if (isVisible) {
    section.style.display = 'block';
    if (matchesData.length === 0) { fetchMatches(); }
    else if (document.getElementById('matchCards').children.length === 0) { renderMatchCards(); }
  } else { section.style.display = 'none'; }
}

setTimeout(function() {
  fetch(MATCHES_JSON_URL).then(function(r) { return r.ok ? r.json() : []; }).then(function(data) { matchesData = data; }).catch(function(){});
}, 800);
